{
  "name": "project-management-api",
  "version": "1.0.0",
  "description": "A simple Project Management API using Node.js",
  "main": "src/server.js",
  "scripts": {
    "start": "node src/server.js"
  },
  "dependencies": {
    "express": "^4.18.2",
    "supertest": "^6.3.3"
  }
}

const express = require('express');
const crypto = require('node:crypto');

const app = express();
app.use(express.json());

// In-memory repositories
const projectsRepo = {};
const tasksRepo = {};
const membersRepo = {};
const commentsRepo = {};

// Health endpoint
app.get('/health', (req, res) => {
  res.status(200).json({ ok: true });
});

// Projects routes
const projectsRoutes = require('./modules/projects/routes');
projectsRoutes(app, { projectsRepo, tasksRepo, membersRepo, commentsRepo, crypto });

// Tasks routes
const tasksRoutes = require('./modules/tasks/routes');
tasksRoutes(app, { projectsRepo, tasksRepo, membersRepo, commentsRepo, crypto });

// Members routes
const membersRoutes = require('./modules/members/routes');
membersRoutes(app, { projectsRepo, tasksRepo, membersRepo, commentsRepo, crypto });

// Comments routes
const commentsRoutes = require('./modules/comments/routes');
commentsRoutes(app, { projectsRepo, tasksRepo, membersRepo, commentsRepo, crypto });

module.exports = app;

function createProject({ name }, { projectsRepo, crypto }) {
  const id = crypto.randomUUID();
  if (Object.values(projectsRepo).some(p => p.name === name)) {
    throw { code: 'duplicate_project', message: 'Project with this name already exists' };
  }
  projectsRepo[id] = { id, name, tasks: [], members: [] };
  return projectsRepo[id];
}

function getProjects({ projectsRepo }) {
  return Object.values(projectsRepo);
}

function getProjectById(id, { projectsRepo }) {
  const project = projectsRepo[id];
  if (!project) throw { code: 'not_found', message: 'Project not found' };
  return project;
}

module.exports = { createProject, getProjects, getProjectById };

function createTask(projectId, { title }, { projectsRepo, tasksRepo, crypto }) {
  const project = projectsRepo[projectId];
  if (!project) throw { code: 'not_found', message: 'Project not found' };

  const taskId = crypto.randomUUID();
  tasksRepo[taskId] = { id: taskId, title, status: 'pending', comments: [] };
  project.tasks.push(taskId);
  return tasksRepo[taskId];
}

function getTasks(projectId, status, { projectsRepo, tasksRepo }) {
  const project = projectsRepo[projectId];
  if (!project) throw { code: 'not_found', message: 'Project not found' };

  let tasks = project.tasks.map(id => tasksRepo[id]);
  if (status) {
    tasks = tasks.filter(task => task.status === status);
  }
  return tasks;
}

function updateTaskStatus(projectId, taskId, { status }, { projectsRepo, tasksRepo }) {
  const project = projectsRepo[projectId];
  if (!project) throw { code: 'not_found', message: 'Project not found' };

  const task = tasksRepo[taskId];
  if (!task || !project.tasks.includes(taskId)) throw { code: 'not_found', message: 'Task not found' };

  task.status = status;
  return task;
}

module.exports = { createTask, getTasks, updateTaskStatus };

function addMember(projectId, member, { projectsRepo }) {
  const project = projectsRepo[projectId];
  if (!project) throw { code: 'not_found', message: 'Project not found' };

  if (project.members.includes(member)) {
    throw { code: 'duplicate_member', message: 'Member already added to the project' };
  }

  project.members.push(member);
  return project;
}

function getMembers(projectId, { projectsRepo }) {
  const project = projectsRepo[projectId];
  if (!project) throw { code: 'not_found', message: 'Project not found' };

  return project.members;
}

module.exports = { addMember, getMembers };

function createComment(projectId, taskId, { message }, { projectsRepo, tasksRepo, commentsRepo, crypto }) {
  const project = projectsRepo[projectId];
  if (!project) throw { code: 'not_found', message: 'Project not found' };

  const task = tasksRepo[taskId];
  if (!task || !project.tasks.includes(taskId)) throw { code: 'not_found', message: 'Task not found' };

  const commentId = crypto.randomUUID();
  commentsRepo[commentId] = { id: commentId, message };
  task.comments.push(commentId);
  return commentsRepo[commentId];
}

function getComments(projectId, taskId, { projectsRepo, tasksRepo, commentsRepo }) {
  const project = projectsRepo[projectId];
  if (!project) throw { code: 'not_found', message: 'Project not found' };

  const task = tasksRepo[taskId];
  if (!task || !project.tasks.includes(taskId)) throw { code: 'not_found', message: 'Task not found' };

  return task.comments.map(id => commentsRepo[id]);
}

module.exports = { createComment, getComments };
